THE RISK:
{
 "id": "avl-gate-forecloses-large-operator-channel",
 "title": "The Year-1 primary channel sits behind an approved-vendor-list gate that pre-launch entrants historically cannot open in 12 months",
 "narrative": "The venture's stated go-to-market is 'large operators first', and the funnel gives that buyer 40% of PDU spend. But large CE operators procure rack power through approved-vendor lists whose onboarding — factory audit, firmware security review, reference installs, dual-region logistics — is a qualification cycle, not a sales cycle. The incumbent lock is visible in Vertiv's named major-customer roster (Equinix, Telefonica, Vodafone). For a pre-launch entrant, the 0.40 slice is not 'ours to win slowly'; it is procedurally unreachable inside the model's Year-1 clock, and the YAM is keyed on exactly this buyer. The reachable Year-1 mix is the distributor/OEM tail the plan hasn't built.",
 "category": "execution",
 "targetNodes": [
  "cust.operator-large",
  "obtainableFactor"
 ],
 "mechanism": [
  {
   "step": "trigger",
   "text": "Large-operator procurement requires AVL qualification (security audit, factory audit, references) that a pre-launch vendor cannot present on day 1; incumbents already hold these slots per Vertiv's named large-account roster",
   "refs": [
    "digest:cust-mix#c9",
    "profile:Stage",
    "ledger:cust.operator-large"
   ]
  },
  {
   "step": "propagation",
   "text": "The 0.40 buyer-mix figure rests on a misread company-level order stat, not a channel study — nothing in it encodes time-to-qualify; meanwhile the indirect channels that ARE open to a new entrant (master distributor, OEM white-label) carry only 0.13 and 0.22 in the mix",
   "refs": [
    "digest:cust-mix#c0",
    "digest:cust-mix#c8",
    "ledger:cust.distributor",
    "ledger:cust.oem"
   ]
  },
  {
   "step": "model-impact",
   "text": "The large-operator cell is foreclosed for the Year-1 window: excluding cust.operator-large removes the largest buyer slice from reachable scope and the YAM built on it, rather than merely shrinking it",
   "refs": [
    "ledger:cust.operator-large",
    "ledger:obtainableFactor"
   ]
  }
 ],
 "whyMissable": "'Large operators buy direct and are the biggest slice' reads as a strength, and the buyer-mix node looks like a market fact. The ledger has no node for time-to-qualify, so the risk is invisible in every sensitivity band — the mix is right about the market and wrong about the venture's first 12 months.",
 "expectedObviousness": "low",
 "falsifier": "A signed vendor-qualification or framework agreement with at least one CE large operator (colo or hyperscale) within the first two quarters, or documented evidence that a comparable new PDU vendor cleared a large-operator AVL in under 6 months.",
 "likelihood": {
  "value": 0.6,
  "rationale": "Multi-quarter vendor qualification is the documented norm for critical-power hardware at large accounts, and the venture starts with zero references; but some colos run fast-track pilot tracks that could open one account inside the year. [evidence revision: Incumbent lock (named rosters, live Telefonica rPDU relationship) and multi-quarter qualification norms are directly corroborated, while no evidence of a sub-6-month AVL clearance by a new entrant surfaced. Modest upward revision from 0.5, bounded because the results confirm the general norm rather than the specific Year-1 foreclosure outcome, and fast-track colo pilot tracks remain a plausible (undocumented but not refuted) escape.]",
  "basis": "evidence",
  "revisedFrom": 0.5
 },
 "perturbation": [
  {
   "nodeId": "cust.operator-large",
   "op": "exclude",
   "note": "Large-operator direct channel foreclosed for the Year-1 window — unreachable, not merely slow"
  }
 ],
 "indicators": [
  {
   "signal": "Stated supplier-onboarding lead time and prerequisites (audits, references, insurance) for new hardware vendors",
   "where": "Equinix, Digital Realty and Vantage EMEA supplier-registration portals; procurement annexes in TED-listed DC fit-out tenders",
   "threshold": ">6 months from registration to RFQ eligibility, or mandatory reference installs",
   "updates": "increases"
  },
  {
   "signal": "Preferred-vendor or sole-source language for rack power at large CE accounts",
   "where": "Vertiv/Schneider EMEA partner-program documents and quarterly earnings commentary on framework agreements",
   "threshold": "Multi-year rack-power frameworks announced at ≥2 flagship CE operators",
   "updates": "increases"
  }
 ],
 "mitigations": [
  {
   "action": "Run 3 structured CE operator procurement interviews focused specifically on AVL cycle length and entry prerequisites for a new PDU vendor",
   "type": "information",
   "voiNodeId": "cust.operator-large",
   "note": "Directly replaces the internally-estimated 0.40 with an evidence-based reachable share and a qualification clock"
  },
  {
   "action": "Re-sequence Year-1 GTM through master-distributor and OEM white-label channels while running large-operator qualification in parallel",
   "type": "strategic",
   "voiNodeId": null,
   "note": "Converts the foreclosed slice into a Year-2 target instead of a Year-1 dependency"
  },
  {
   "action": "Negotiate a paid pilot MOU with one mid-size CE colo that contractually feeds its AVL process",
   "type": "contractual",
   "voiNodeId": null,
   "note": "Buys a reference install — the scarcest qualification asset"
  }
 ],
 "evidenceStatus": "corroborated",
 "evidence": [
  {
   "title": "Vertiv Partner Program (Major Customers roster)",
   "sourceType": "industry-report",
   "publisher": "Vertiv",
   "date": "2024",
   "excerpt": "MAJOR CUSTOMERS Alibaba, Alstom, America Movil, AT&T, China Mobile, Equinix, Ericsson, Reliance, Siemens, Telefonica, Tencent, Verizon and Vodafone",
   "url": "https://www.vertiv.com/49858a/globalassets/documents/brochures/vertiv-partner-program-emea-2024-en.pdf",
   "attached": true
  },
  {
   "title": "Certification Lead-Time Matrix for Data Center and IT Hardware",
   "sourceType": "industry-report",
   "publisher": "TFTIOR",
   "date": "2026-05-10",
   "excerpt": "new model certification can take six months or longer. A project that books freight before confirming certification status in these jurisdictions does not save time.",
   "url": "https://tftior.com/certification-lead-time-matrix/",
   "attached": true
  },
  {
   "title": "Vertiv Global Supplier Quality Manual",
   "sourceType": "industry-report",
   "publisher": "Vertiv",
   "date": "2023-08-21",
   "excerpt": "Process for new supplier Qualifications ... Requirements for Purchased Part Approval Process ... Supplier Quality Management System",
   "url": "https://www.vertiv.com/48edc7/globalassets/documents/manuals/vertiv-global-supplier-quality-manual_283844_02.pdf",
   "attached": true
  }
 ],
 "stances": [
  {
   "url": "https://www.vertiv.com/49858a/globalassets/documents/brochures/vertiv-partner-program-emea-2024-en.pdf",
   "stance": "supports",
   "quote": "MAJOR CUSTOMERS Alibaba, Alstom, America Movil, AT&T, China Mobile, Equinix, Ericsson, Reliance, Siemens, Telefonica, Tencent, Verizon and Vodafone"
  },
  {
   "url": "https://www.vertiv.com/en-emea/about/news-and-events/articles/case-studies/2026/telefonica-germany-upgrades-data-center-operations-with-vertiv-powerit-rpdus-for-enhanced-real-time-monitoring/",
   "stance": "supports",
   "quote": "Telefónica Germany upgrades data center operations with Vertiv™ PowerIT rPDUs for enhanced real-time monitoring"
  },
  {
   "url": "https://www.vertiv.com/48edc7/globalassets/documents/manuals/vertiv-global-supplier-quality-manual_283844_02.pdf",
   "stance": "supports",
   "quote": "7. Requirement for Supplier Approval 6 \n8. Process for new supplier Qualifications 8 \n9. Requirements for Purchased Part Approval Process 10"
  },
  {
   "url": "https://tftior.com/certification-lead-time-matrix/",
   "stance": "supports",
   "quote": "In markets like India and Brazil, new model certification can take six months or longer. A project that books freight before confirming certification status in these jurisdictions does not save time."
  },
  {
   "url": "https://www.servertech.com/solutions/colocation-solutions",
   "stance": "contradicts",
   "quote": "With ready-made rack PDU solutions in as little as 3-5 days plus 12,000 PDU varieties to support your unique requirements, Server Technology has you covered."
  }
 ]
}

